import sys

class Node:
    __slots__ = ('val', 'left', 'right')
    def __init__(self, val: int, left: 'Node' = None, right: 'Node' = None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def flatten(self, head: Node) -> Node:
        if not head:
            return None
        stack = [head]
        prev = None
        new_head = None
        while stack:
            node = stack.pop()
            # push right then left so left is processed first
            if node.right:
                stack.append(node.right)
            if node.left:
                stack.append(node.left)
            node.right = None
            node.left = None
            if prev:
                prev.right = node
            else:
                new_head = node
            prev = node
        return new_head

def build_nodes(tokens):
    n = int(next(tokens))
    nodes = [Node(0) for _ in range(n)]
    children = []
    for i in range(n):
        val = int(next(tokens))
        left_idx = int(next(tokens))
        right_idx = int(next(tokens))
        nodes[i].val = val
        children.append((left_idx, right_idx))
    for i, (l, r) in enumerate(children):
        if l != -1:
            nodes[i].left = nodes[l]
        if r != -1:
            nodes[i].right = nodes[r]
    return nodes[0] if n else None

if __name__ == '__main__':
    data = sys.stdin.read().split()
    if not data:
        sys.exit(0)
    it = iter(data)
    head = build_nodes(it)
    sol = Solution()
    new_head = sol.flatten(head)
    # collect values
    vals = []
    cur = new_head
    while cur:
        vals.append(str(cur.val))
        cur = cur.right
    print(len(vals))
    if vals:
        print(' '.join(vals))

