#include <bits/stdc++.h>
using namespace std;

struct Node {
    int val;
    Node* left;
    Node* right;
    Node(int v=0): val(v), left(nullptr), right(nullptr) {}
};

class Solution {
public:
    Node* flatten(Node* head) {
        if (!head) return nullptr;
        vector<Node*> st;
        st.push_back(head);
        Node* prev = nullptr;
        Node* new_head = nullptr;
        while (!st.empty()) {
            Node* node = st.back();
            st.pop_back();
            if (node->right) st.push_back(node->right);
            if (node->left) st.push_back(node->left);
            node->left = nullptr;
            node->right = nullptr;
            if (prev) prev->right = node;
            else new_head = node;
            prev = node;
        }
        return new_head;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<Node*> nodes(n);
    vector<pair<int,int>> childs(n);
    for (int i = 0; i < n; ++i) {
        int val, l, r;
        cin >> val >> l >> r;
        nodes[i] = new Node(val);
        childs[i] = {l, r};
    }
    for (int i = 0; i < n; ++i) {
        int l = childs[i].first, r = childs[i].second;
        if (l != -1) nodes[i]->left = nodes[l];
        if (r != -1) nodes[i]->right = nodes[r];
    }
    Node* head = n ? nodes[0] : nullptr;
    Solution sol;
    Node* new_head = sol.flatten(head);
    vector<int> vals;
    for (Node* cur = new_head; cur; cur = cur->right) vals.push_back(cur->val);
    cout << vals.size() << "\n";
    for (size_t i = 0; i < vals.size(); ++i) {
        if (i) cout << ' ';
        cout << vals[i];
    }
    if (!vals.empty()) cout << "\n";
    return 0;
}
